(function(){
  try {
    var buttons = document.querySelectorAll('button');
    var result = [];
    for (var i = 0; i < buttons.length; i++) {
      result.push({index: i, text: buttons[i].textContent.trim()});
    }
    return JSON.stringify(result);
  } catch(e) {
    return JSON.stringify({error: e.message});
  }
})()
